  ('heelevel3-e3452428-moex-00166', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-112-3a7b2121', 'sub-heelevel3-e3452428-03', NULL, 'single_choice', '政府採用民營化措施推動公共服務時，最可能出現下列那一項缺點？', '["資源運用效率低落", "公共責任難以釐清", "政府職能大幅擴張", "服務品質明顯劣化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:45+00:00", "source_pdf_sha1": "7f7320bb621b", "answer_pdf_sha1": "83680f2f574d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "301", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00167', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-112-3a7b2121', 'sub-heelevel3-e3452428-03', NULL, 'single_choice', '下列何者比較不適用於解釋地方政府之間跨域協調不力的原因？', '["黨派競爭與黨同伐異", "管轄權認定不同", "地方公民素質不佳", "權責劃分不清"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:45+00:00", "source_pdf_sha1": "7f7320bb621b", "answer_pdf_sha1": "83680f2f574d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "301", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00168', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-112-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'essay', 'A市政府為管理市內攤販經營事業，制定攤販管理自治條例。其中規定，
攤販經營許可申請，如涉及私人土地，而不違反現行法令規定者，應檢具
所有權人同意書。市民丙申請經營攤販位於他人丁之所有土地上，於申請
時檢附所有權人丁之同意書，市政府發給許可證。於證件背面註記注意事
項：核准設攤地點涉及私人土地經所有權人提出異議時，應於一個月內提
供所有權人同意書，逾期未補正者，本府得註銷許可證之效力。丙開始經
營後，丁欲收回租地，向A市政府表示異議，市政府遂要求丙提出同意書，
逾期將廢止許可證。一個月期間過後，丙未能提出同意書，故市政府以B
函註銷許可證。請問：B函是否合法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:45+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00169', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-112-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'essay', '甲檢具陳情書向某政府乙機關陳情，主張甲所有建物（下稱系爭建物）之
相鄰建物違法施工裝潢，因其室內裝修廠商未具施工許可證，為保障系爭
建物之安全，乃訴求乙禁止相鄰建物繼續施工。乙回復甲略以：經查系爭
建物之相鄰建物，業已委託設計建築師及合格室內裝修廠商施工，其施工
期間及竣工查驗之結構安全，併由設計建築師簽證負責；且該址業由審查
機構之審查人員辦理竣工審查，並取得室內裝修合格證明在案等語。甲不
服，循序提起行政訴訟。試問：甲有無請求乙對檢舉內容為事實調查予以
裁罰之公法上請求權，並具提起行政訴訟之原告適格？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:45+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00170', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-112-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'single_choice', '下列何者為行政法之不成文法源？', '["行政規則", "國際條約", "公益原則", "自治規章"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:45+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00171', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-112-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'single_choice', '供公眾使用之建築物，違反建築法第77條規定，未定期辦理公共安全檢查簽證及申報，行政機關違反 先前先通知當事人補辦程序之慣例，即逕行採取裁罰措施，係違反何種行政法一般原理原則？', '["平等原則", "比例原則", "禁止不當聯結原則", "法律優位原則 31550、31650 32250、32950 33050 33850"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:45+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00172', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-112-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'single_choice', '依據實務見解，納稅義務人因違反稅法規定而受罰鍰處分，惟納稅義務人於行政訴訟程序中死亡， 則罰鍰處分應如何處置？', '["因納稅義務人死亡，法律關係即告消滅，故無法執行該罰鍰處分", "由繼承人繼承被繼承人之義務人地位，並繳納罰鍰", "納稅義務人死亡後，法院應以欠缺當事人能力為由駁回訴訟", "由繼承人於被繼承人遺產範圍內代繳罰鍰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:45+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00173', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-112-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'single_choice', '關於國家表演藝術中心在組織及任務上之特性，不包括下列何者？', '["負執行公共事務之任務", "具有獨立之法律人格", "以企業化之方式營運", "所屬人員均具公務人員身分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:45+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00174', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-112-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'single_choice', '依地方制度法規定，中央主管機關針對直轄市政府所辦理自治事項之監督，下列敘述何者錯誤？', '["地方政府辦理自治事項得自為立法並執行而負其政策規劃及行政執行責任", "地方政府辦理自治事項有違憲法或法律規定時，仍得予以撤銷、變更、廢止或停止其執行", "直轄市政府辦理自治事項違法時，由中央主管機關報行政院予以撤銷、變更、廢止或停止其執行", "地方政府辦理自治事項若有違背憲法或法律之疑義時，於司法院解釋前，中央主管機關得先予 以撤銷之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:45+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00175', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-112-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'single_choice', '關於機關權限之敘述，下列何者錯誤？', '["行政機關欲將部分權限委託不相隸屬之行政機關執行，係屬職權事項，故主管機關得依職權辦 理權限之委託", "行政機關將作成行政處分權限移轉予他機關時，則撤銷權之行使，應於權限移轉後改由承受其 業務機關為之", "行政處分無效事由之所謂「缺乏事務管轄權限」，應限縮於重大明顯之情事", "行政機關得依法規將部分權限委任相隸屬之行政機關執行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:45+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL)
